parameters.jsCode:
const body = $json.body ?? $json;
const workflowMode = body.workflow_mode ?? 'auto_trending';
const topicHint = body.topic_hint || 'Topik hangat';
const normalizedTopic = String(topicHint || '').trim() || 'teknologi';
const numClips = Math.min(Math.max(Number(body.num_clips || 1), 1), 10);
const clipDuration = Math.min(Math.max(Number(body.clip_duration || 30), 20), 60);

const youtubeUrl = body.youtube_url;
const isManual = workflowMode === 'manual_url';

const hookTemplates = [
  'MOMEN PALING PANAS',
  'PENDAPAT PALING BERANI',
  'INSIGHT YANG JARANG DIBAHAS',
  'BAGIAN YANG BIKIN MIKIR',
  'KALIMAT PALING MENOHOK',
  'PREDIKSI PALING MENARIK'
];
const smartOffsets = [45, 120, 210, 300, 390, 480, 570, 660, 750, 840];

const providedPlans = Array.isArray(body.clips_plan) ? body.clips_plan : [];
let clipsPlan = [];

if (!isManual || providedPlans.length > 0) {
  for (let i = 0; i < numClips; i++) {
    const clipNumber = i + 1;
    const hook = hookTemplates[i % hookTemplates.length];
    const provided = providedPlans[i] || null;
    const start = Number(provided?.start_time ?? smartOffsets[i] ?? (45 + i * clipDuration));
    const end = Number(provided?.end_time ?? (start + clipDuration));

    clipsPlan.push({
      clip_number: clipNumber,
      title: provided?.title || `${normalizedTopic} - ${hook}`,
      subtitle_text: provided?.subtitle_text || `${hook}: ${normalizedTopic}`,
      start_time: start,
      end_time: end,
      duration: Number(provided?.duration ?? clipDuration),
      reason: provided?.reason || 'Segment dipilih karena hook conversation yang kuat untuk Shorts.'
    });
  }
}

const excludeTerms = '-pertandingan -live -highlight -highlights -gol -goal';
const sourcePodcastQuery = `podcast ${normalizedTopic} indonesia ${excludeTerms}`;

const sourceCandidateQueries = [
  `podcast ${normalizedTopic} indonesia full episode ${excludeTerms}`,
  `podcast ${normalizedTopic} indonesia terbaru ${excludeTerms}`,
  `podcast close the door ${normalizedTopic} ${excludeTerms}`,
  `podcast denny sumargo ${normalizedTopic} ${excludeTerms}`,
  `podcast najwa shihab ${normalizedTopic} ${excludeTerms}`,
  `podcast vindes ${normalizedTopic} ${excludeTerms}`,
  `wawancara ${normalizedTopic} podcast indonesia ${excludeTerms}`
];

return [{
  json: {
    task_id: Number(body.task_id),
    workflow_mode: workflowMode,
    youtube_url: youtubeUrl,
    num_clips: numClips,
    watermark_url: body.watermark_url || null,
    callback_url: body.callback_url || 'https://clipper.dimascndraa.me/api/ai-clipper/callback',
    render_upload_url: body.render_upload_url || 'https://clipper.dimascndraa.me/api/ai-clipper/render-upload',
    render_api_key: body.render_api_key || '123456',
    ai_enhance: body.ai_enhance ?? true,
    ai_model: body.ai_model || 'gpt-4o-mini',
    auto_clip_find: body.auto_clip_find ?? isManual,
    face_tracking: body.face_tracking ?? true,
    face_tracking_required: body.face_tracking_required ?? false,
    face_tracking_smoothness: Number(body.face_tracking_smoothness ?? 0.88),
    topic_hint: normalizedTopic,
    fact_check_notes: `Topik ${normalizedTopic} divalidasi dari beberapa sumber tepercaya.`,
    source_podcast_query: sourcePodcastQuery,
    source_candidate_queries: sourceCandidateQueries,
    clips_plan: clipsPlan
  }
}];

const render = $json;

if (render.status !== 'completed') {
  return [{
    json: {
      task_id: Number(render.task_id || 0),
      callback_url: render.callback_url || 'https://clipper.dimascndraa.me/api/ai-clipper/callback',
      status: 'failed',
      error: render.error || 'Render/upload failed in render-upload endpoint.',
      youtube_publish_status: 'failed'
    }
  }];
}

return [{
  json: {
    task_id: Number(render.task_id),
    callback_url: render.callback_url,
    status: 'completed',
    total_clips: Number(render.total_clips || 0),
    clips: render.rendered_clips || [],
    fact_check_notes: render.fact_check_notes || null,
    source_podcast_query: render.source_podcast_query || null,
    youtube_publish_status: 'review_pending'
  }
}];

